import{_ as s,o as n,c as i,a4 as e}from"./chunks/framework.BhEBm8_q.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/Linux 服务器部署运行 Python app.py 完整教程（后台常驻 + 环境配置 + 权限修复）.md","filePath":"docs/Linux 服务器部署运行 Python app.py 完整教程（后台常驻 + 环境配置 + 权限修复）.md"}'),p={name:"docs/Linux 服务器部署运行 Python app.py 完整教程（后台常驻 + 环境配置 + 权限修复）.md"};function l(t,a,h,o,d,c){return n(),i("div",null,[...a[0]||(a[0]=[e(`<p>本文适用于 <strong>Termius 远程连接 Linux 服务器</strong>，解决 Python 环境搭建、代码格式报错、权限不足、关闭终端程序停止运行等问题，实现 <code>app.py</code> 永久后台常驻运行。</p><h2 id="一、安装-python-基础环境" tabindex="-1">一、安装 Python 基础环境 <a class="header-anchor" href="#一、安装-python-基础环境" aria-label="Permalink to “一、安装 Python 基础环境”">​</a></h2><p>确保服务器自带 Python3，安装虚拟环境依赖</p><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 更新软件源</span></span>
<span class="line"><span>sudo apt update</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 安装 python3 虚拟环境组件</span></span>
<span class="line"><span>sudo apt install python3.10-venv -y</span></span></code></pre></div><h2 id="二、创建-python-虚拟环境" tabindex="-1">二、创建 Python 虚拟环境 <a class="header-anchor" href="#二、创建-python-虚拟环境" aria-label="Permalink to “二、创建 Python 虚拟环境”">​</a></h2><p>统一环境依赖，避免全局包冲突</p><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 创建虚拟环境（文件夹名统一为 MyVenv）</span></span>
<span class="line"><span>python3 -m venv MyVenv</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 激活 Linux 虚拟环境</span></span>
<span class="line"><span>source MyVenv/bin/activate</span></span></code></pre></div><p>激活成功后，终端前缀会显示 <code>(MyVenv)</code></p><h2 id="三、安装项目依赖库与工具" tabindex="-1">三、安装项目依赖库与工具 <a class="header-anchor" href="#三、安装项目依赖库与工具" aria-label="Permalink to “三、安装项目依赖库与工具”">​</a></h2><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 安装图像处理 PIL 库</span></span>
<span class="line"><span>pip install Pillow</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 安装换行格式转换工具（解决 Windows 脚本上传 Linux 报错）</span></span>
<span class="line"><span>sudo apt-get install dos2unix -y</span></span></code></pre></div><h2 id="四、修复-windows-转-linux-代码格式报错" tabindex="-1">四、修复 Windows 转 Linux 代码格式报错 <a class="header-anchor" href="#四、修复-windows-转-linux-代码格式报错" aria-label="Permalink to “四、修复 Windows 转 Linux 代码格式报错”">​</a></h2><p>本地 Windows 编写的 <code>app.py</code> 上传服务器会出现换行符异常、解析失败，需要格式转换</p><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 转换文件编码与换行格式</span></span>
<span class="line"><span>dos2unix app.py</span></span></code></pre></div><h2 id="五、赋予脚本执行权限" tabindex="-1">五、赋予脚本执行权限 <a class="header-anchor" href="#五、赋予脚本执行权限" aria-label="Permalink to “五、赋予脚本执行权限”">​</a></h2><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 给 app.py 添加可执行权限</span></span>
<span class="line"><span>chmod +x app.py</span></span></code></pre></div><h2 id="六、解决关闭-termius-程序停止问题-重点" tabindex="-1">六、解决关闭 Termius 程序停止问题（重点） <a class="header-anchor" href="#六、解决关闭-termius-程序停止问题-重点" aria-label="Permalink to “六、解决关闭 Termius 程序停止问题（重点）”">​</a></h2><h3 id="问题原因" tabindex="-1">问题原因 <a class="header-anchor" href="#问题原因" aria-label="Permalink to “问题原因”">​</a></h3><p>直接在终端运行<code>python3 app.py</code>，属于<strong>前台进程</strong>，关闭 Termius 终端、断开 SSH 连接，系统会发送挂起信号，程序直接终止。</p><h3 id="后台常驻运行命令-永久生效" tabindex="-1">后台常驻运行命令（永久生效） <a class="header-anchor" href="#后台常驻运行命令-永久生效" aria-label="Permalink to “后台常驻运行命令（永久生效）”">​</a></h3><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># nohup 后台运行，忽略挂断信号，退出终端不停止</span></span>
<span class="line"><span>nohup python3 app.py</span></span></code></pre></div><h3 id="命令说明" tabindex="-1">命令说明 <a class="header-anchor" href="#命令说明" aria-label="Permalink to “命令说明”">​</a></h3><ul><li><p><code>nohup</code>：让进程忽略 SIGHUP 挂起信号，关闭终端不退出</p></li><li><p>&amp;：放入后台运行</p></li><li><p>自动生成 <code>nohup.out</code> 文件，存储程序所有日志、报错、输出信息</p></li></ul><h2 id="七、查看程序运行状态与日志" tabindex="-1">七、查看程序运行状态与日志 <a class="header-anchor" href="#七、查看程序运行状态与日志" aria-label="Permalink to “七、查看程序运行状态与日志”">​</a></h2><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 实时查看运行日志</span></span>
<span class="line"><span>tail -f nohup.out</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看全部日志内容</span></span>
<span class="line"><span>cat nohup.out</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看 Python 后台进程是否在运行</span></span>
<span class="line"><span>ps -ef | grep app.py</span></span></code></pre></div><h2 id="八、停止后台运行的程序" tabindex="-1">八、停止后台运行的程序 <a class="header-anchor" href="#八、停止后台运行的程序" aria-label="Permalink to “八、停止后台运行的程序”">​</a></h2><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 先查询进程 PID</span></span>
<span class="line"><span>ps -ef | grep app.py</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 杀死进程（替换 PID 为查到的数字）</span></span>
<span class="line"><span>kill -9 PID</span></span></code></pre></div><h2 id="九、全套启动总结-一键流程" tabindex="-1">九、全套启动总结（一键流程） <a class="header-anchor" href="#九、全套启动总结-一键流程" aria-label="Permalink to “九、全套启动总结（一键流程）”">​</a></h2><div class="language-Plain"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>source MyVenv/bin/activate</span></span>
<span class="line"><span>dos2unix app.py</span></span>
<span class="line"><span>chmod +x app.py</span></span>
<span class="line"><span>nohup python3 app.py</span></span></code></pre></div>`,28)])])}const k=s(p,[["render",l]]);export{g as __pageData,k as default};
